  1→/**
  2→ * App.jsx - Main application component
  3→ * 코드 스플리팅 적용 (React.lazy + Suspense)
  4→ */
  5→import { lazy, Suspense, useEffect } from 'react';
  6→import { BrowserRouter, Routes, Route, Navigate, useParams, useLocation } from 'react-router-dom';
  7→import { trackPageView } from './utils/analytics';
  8→import { UserProvider, useUser } from './contexts/UserContext';
  9→import { PortfolioProvider } from './contexts/PortfolioContext';
 10→import { TutorProvider } from './contexts/TutorContext';
 11→import { TermProvider } from './contexts/TermContext';
 12→import { ThemeProvider } from './contexts/ThemeContext';
 13→import { TutorModal, ErrorBoundary, ToastProvider } from './components';
 14→import TermBottomSheet from './components/domain/TermBottomSheet';
 15→import BottomNav from './components/layout/BottomNav';
 16→import AgentDock from './components/agent/AgentDock';
 17→import PenguinLoading from './components/common/PenguinLoading';
 18→import UpdatePrompt from './components/common/UpdatePrompt';
 19→import UpdateNotice from './components/common/UpdateNotice';
 20→
 21→// 코드 스플리팅: 각 페이지를 동적 import
 22→const Auth = lazy(() => import('./pages/Auth'));
 23→const Landing = lazy(() => import('./pages/Landing'));
 24→const Home = lazy(() => import('./pages/Home'));
 25→const Education = lazy(() => import('./pages/Education'));
 26→const ActivityArchive = lazy(() => import('./pages/ActivityArchive'));
 27→const Search = lazy(() => import('./pages/Search'));
 28→const Comparison = lazy(() => import('./pages/Comparison'));
 29→const Story = lazy(() => import('./pages/Story'));
 30→const Companies = lazy(() => import('./pages/Companies'));
 31→const History = lazy(() => import('./pages/History'));
 32→const Narrative = lazy(() => import('./pages/Narrative'));
 33→const Notifications = lazy(() => import('./pages/Notifications'));
 34→const Portfolio = lazy(() => import('./pages/Portfolio'));
 35→const Profile = lazy(() => import('./pages/Profile'));
 36→const TutorChat = lazy(() => import('./pages/TutorChat'));
 37→const AgentCanvasPage = lazy(() => import('./pages/AgentCanvasPage'));
 38→const AgentHistoryPage = lazy(() => import('./pages/AgentHistoryPage'));
 39→const FeedbackSurvey = lazy(() => import('./pages/FeedbackSurvey'));
 40→
 41→function CaseRedirect() {
 42→  const { caseId } = useParams();
 43→  if (!caseId) return <Navigate to="/search" replace />;
 44→  return <Navigate to={`/narrative/${caseId}`} replace />;
 45→}
 46→
 47→function ProtectedRoute({ children }) {
 48→  const { user, isLoading } = useUser();
 49→  if (isLoading) return <PageLoader />;
 50→  if (!user?.isAuthenticated) return <Navigate to="/" replace />;
 51→  return children;
 52→}
 53→
 54→function PageLoader() {
 55→  return (
 56→    <div className="min-h-screen bg-background flex items-center justify-center">
 57→      <PenguinLoading size="sm" />
 58→    </div>
 59→  );
 60→}
 61→
 62→function PageViewTracker() {
 63→  const location = useLocation();
 64→  useEffect(() => {
 65→    trackPageView(location.pathname);
 66→  }, [location.pathname]);
 67→  return null;
 68→}
 69→
 70→function AppRoutes() {
 71→  return (
 72→    <Suspense fallback={<PageLoader />}>
 73→      <Routes>
 74→        <Route path="/" element={<Landing />} />
 75→        <Route path="/landing" element={<Navigate to="/" replace />} />
 76→        <Route path="/onboarding" element={<Navigate to="/" replace />} />
 77→        <Route path="/auth" element={<Auth />} />
 78→        <Route path="/education" element={<ProtectedRoute><Education /></ProtectedRoute>} />
 79→        <Route path="/education/archive" element={<ProtectedRoute><ActivityArchive /></ProtectedRoute>} />
 80→        <Route path="/home" element={<ProtectedRoute><Home /></ProtectedRoute>} />
 81→        <Route path="/search" element={<ProtectedRoute><Search /></ProtectedRoute>} />
 82→        <Route path="/comparison" element={<ProtectedRoute><Comparison /></ProtectedRoute>} />
 83→        <Route path="/story" element={<ProtectedRoute><Story /></ProtectedRoute>} />
 84→        <Route path="/companies" element={<ProtectedRoute><Companies /></ProtectedRoute>} />
 85→        <Route path="/history" element={<ProtectedRoute><History /></ProtectedRoute>} />
 86→        <Route path="/case/:caseId" element={<ProtectedRoute><CaseRedirect /></ProtectedRoute>} />
 87→        <Route path="/narrative/:caseId" element={<ProtectedRoute><Narrative /></ProtectedRoute>} />
 88→        <Route path="/notifications" element={<ProtectedRoute><Notifications /></ProtectedRoute>} />
 89→        <Route path="/portfolio" element={<ProtectedRoute><Portfolio /></ProtectedRoute>} />
 90→        <Route path="/profile" element={<ProtectedRoute><Profile /></ProtectedRoute>} />
 91→        <Route path="/tutor" element={<ProtectedRoute><TutorChat /></ProtectedRoute>} />
 92→        <Route path="/agent" element={<ProtectedRoute><AgentCanvasPage /></ProtectedRoute>} />
 93→        <Route path="/agent/history" element={<ProtectedRoute><AgentHistoryPage /></ProtectedRoute>} />
 94→        <Route path="/feedback-survey" element={<ProtectedRoute><FeedbackSurvey /></ProtectedRoute>} />
 95→        <Route path="*" element={<Navigate to="/" replace />} />
 96→      </Routes>
 97→    </Suspense>
 98→  );
 99→}
100→
101→export default function App() {
102→  return (
103→    <BrowserRouter>
104→      <ThemeProvider>
105→        <UserProvider>
106→          <PortfolioProvider>
107→          <TutorProvider>
108→            <TermProvider>
109→              <ErrorBoundary>
110→                <ToastProvider>
111→                  <PageViewTracker />
112→                  <div className="app-container">
113→                    <UpdatePrompt />
114→                    <UpdateNotice />
115→                    <AppRoutes />
116→                    <TermBottomSheet />
117→                    <TutorModal />
118→                    <AgentDock />
119→                    <BottomNav />
120→                  </div>
121→                </ToastProvider>
122→              </ErrorBoundary>
123→            </TermProvider>
124→          </TutorProvider>
125→          </PortfolioProvider>
126→        </UserProvider>
127→      </ThemeProvider>
128→    </BrowserRouter>
129→  );
130→}
