 18→/**
 19→ * useTutor — 하위 호환 wrapper.
 20→ * 기존 컴포넌트에서 useTutor()를 그대로 사용할 수 있도록 3개 context를 합쳐 반환.
 21→ * 고성능이 필요한 경우 useTutorChat()/useTutorSession()/useTutorUI() 각각 사용.
 22→ */
 23→export function useTutor() {
 24→  const ui = useTutorUI();
 25→  const session = useTutorSession();
 26→  const chat = useTutorChat();
 27→
 28→  const {
 29→    openTutor: openTutorUI,
 30→    closeTutor,
 31→    contextInfo,
 32→    setContextInfo,
 33→    currentTerm,
 34→    setCurrentTerm,
 35→    agentStatus,
 36→    setAgentStatus,
 37→    requestVisualization: requestVisualizationUI,
 38→    DEFAULT_AGENT_STATUS,
 39→  } = ui;
 40→  const {
 41→    sessions,
 42→    activeSessionId,
 43→    refreshSessions,
 44→    createNewChat: createNewChatSession,
 45→    deleteChat: deleteChatSession,
 46→    setActiveSessionId,
 47→  } = session;
 48→  const {
 49→    messages,
 50→    assistantTurns,
 51→    isLoading,
 52→    isStreamingActive,
 53→    canRegenerate,
 54→    sessionId,
 55→    sendMessage: sendChatMessage,
 56→    stopGeneration: stopGenerationRaw,
 57→    regenerateLastResponse: regenerateLastResponseRaw,
 58→    clearMessages: clearChatMessages,
 59→    loadChatHistory: loadChatHistoryRaw,
 60→    setSessionId,
 61→  } = chat;
 62→
 63→  const openTutor = useCallback((termOrContext = null) => {
 64→    openTutorUI(termOrContext, refreshSessions);
 65→  }, [openTutorUI, refreshSessions]);
 66→
 67→  const createNewChat = useCallback(async () => {
 68→    return createNewChatSession((nextSessionId) => {
 69→      clearChatMessages();
 70→      setCurrentTerm(null);
 71→      setAgentStatus(DEFAULT_AGENT_STATUS);
 72→      setSessionId(nextSessionId);
 73→      setActiveSessionId(nextSessionId);
 74→    });
 75→  }, [createNewChatSession, clearChatMessages, setCurrentTerm, setAgentStatus, DEFAULT_AGENT_STATUS, setSessionId, setActiveSessionId]);
 76→
 77→  const deleteChat = useCallback(async (id) => {
 78→    return deleteChatSession(id, () => {
 79→      clearChatMessages();
 80→      setSessionId(null);
 81→      setCurrentTerm(null);
 82→      setAgentStatus(DEFAULT_AGENT_STATUS);
 83→    });
 84→  }, [deleteChatSession, clearChatMessages, setSessionId, setCurrentTerm, setAgentStatus, DEFAULT_AGENT_STATUS]);
 85→
 86→  const loadChatHistory = useCallback(async (id) => {
 87→    return loadChatHistoryRaw(id, setActiveSessionId);
 88→  }, [loadChatHistoryRaw, setActiveSessionId]);
 89→
 90→  const sendMessage = useCallback(async (message, difficulty = 'beginner', options = {}) => {
 91→    const contextInfoToUse = options?.contextInfoOverride || contextInfo;
 92→    const chatOptions = options?.chatOptions || options;
 93→    await sendChatMessage(
 94→      message,
 95→      difficulty,
 96→      contextInfoToUse,
 97→      setAgentStatus,
 98→      (newSessionId) => {
 99→        setActiveSessionId(newSessionId);
100→      },
101→      chatOptions,
102→    );
103→    await refreshSessions();
104→  }, [sendChatMessage, contextInfo, setAgentStatus, setActiveSessionId, refreshSessions]);
105→
106→  const stopGeneration = useCallback(() => {
107→    return stopGenerationRaw();
108→  }, [stopGenerationRaw]);
109→
110→  const regenerateLastResponse = useCallback(async (options = {}) => {
111→    const success = await regenerateLastResponseRaw(
112→      setAgentStatus,
113→      (newSessionId) => {
114→        setActiveSessionId(newSessionId);
115→      },
116→      {
117→        difficulty: options?.difficulty,
118→        contextInfo: options?.contextInfoOverride || contextInfo,
119→        options: options?.chatOptions,
120→      },
121→    );
122→
123→    if (success) {
124→      await refreshSessions();
125→    }
126→
127→    return success;
128→  }, [regenerateLastResponseRaw, setAgentStatus, setActiveSessionId, contextInfo, refreshSessions]);
129→
130→  const requestVisualization = useCallback((query) => {
131→    requestVisualizationUI(query, (msg, diff) => sendMessage(msg, diff));
132→  }, [requestVisualizationUI, sendMessage]);
133→
134→  const clearMessages = useCallback(() => {
135→    clearChatMessages();
136→    setCurrentTerm(null);
137→    setActiveSessionId(null);
138→    setAgentStatus(DEFAULT_AGENT_STATUS);
139→  }, [clearChatMessages, setCurrentTerm, setActiveSessionId, setAgentStatus, DEFAULT_AGENT_STATUS]);
140→
141→  return {
142→    // UI
143→    isOpen: ui.isOpen,
144→    openTutor,
145→    closeTutor,
146→    contextInfo,
147→    setContextInfo,
148→    currentTerm,
149→    setCurrentTerm,
150→    agentStatus,
151→    requestVisualization,
152→    // Session
153→    sessions,
154→    activeSessionId,
155→    refreshSessions,
156→    createNewChat,
157→    deleteChat,
158→    // Chat
159→    messages,
160→    assistantTurns,
161→    isLoading,
162→    isStreamingActive,
163→    canRegenerate,
164→    sessionId,
165→    sendMessage,
166→    stopGeneration,
167→    regenerateLastResponse,
168→    clearMessages,
169→    loadChatHistory,
170→  };
171→}
