 1→/**
 2→ * TermContext.jsx - 용어 바텀시트 상태 관리
 3→ * 하이라이트된 용어 클릭 시 바텀시트를 열고, 필요 시 AI 튜터로 연결
 4→ */
 5→import { createContext, useContext, useState, useCallback, useMemo } from 'react';
 6→import { useTutor } from './TutorContext';
 7→
 8→const TermContext = createContext(null);
 9→
10→export function TermProvider({ children }) {
11→  const [selectedTerm, setSelectedTerm] = useState(null);
12→  const [isTermSheetOpen, setIsTermSheetOpen] = useState(false);
13→  const { openTutor } = useTutor();
14→
15→  // 바텀시트 열기
16→  const openTermSheet = useCallback((term) => {
17→    setSelectedTerm(term);
18→    setIsTermSheetOpen(true);
19→  }, []);
20→
21→  // 바텀시트 닫기
22→  const closeTermSheet = useCallback(() => {
23→    setIsTermSheetOpen(false);
24→    setSelectedTerm(null);
25→  }, []);
26→
27→  // 바텀시트 닫고 AI 튜터 채팅으로 이동
28→  const openTutorWithTerm = useCallback((term) => {
29→    setIsTermSheetOpen(false);
30→    setSelectedTerm(null);
31→    openTutor(term);
32→  }, [openTutor]);
33→
34→  const value = useMemo(() => ({
35→    selectedTerm,
36→    isTermSheetOpen,
37→    openTermSheet,
38→    closeTermSheet,
39→    openTutorWithTerm,
40→  }), [selectedTerm, isTermSheetOpen, openTermSheet, closeTermSheet, openTutorWithTerm]);
41→
42→  return (
43→    <TermContext.Provider value={value}>
44→      {children}
45→    </TermContext.Provider>
46→  );
47→}
48→
49→export function useTermContext() {
50→  const context = useContext(TermContext);
51→  if (!context) throw new Error('useTermContext must be used within a TermProvider');
52→  return context;
53→}
