241→      setAssistantTurns((prev) => [
242→        ...prev,
243→        {
244→          id: turnId,
245→          assistantMessageId: assistantMessage.id,
246→          userPrompt: normalizedMessage,
247→          assistantText: '',
248→          status: 'streaming',
249→          createdAt: assistantMessage.timestamp,
250→          sources: [],
251→          uiActions: [],
252→          model: null,
253→          structured: null,
254→          guardrailNotice: null,
255→          guardrailDecision: null,
256→          guardrailMode: null,
257→        },
258→      ]);
259→
260→      const syncAssistantState = (nextContent, options = {}) => {
261→        const {
262→          isStreaming = true,
263→          isError = false,
264→          sources = pendingSources,
265→          uiActions = pendingUiActions,
266→          model = pendingModel,
267→          structured = pendingStructured,
268→          guardrailNotice = pendingGuardrailNotice,
269→          guardrailDecision = pendingGuardrailDecision,
270→          guardrailMode = pendingGuardrailMode,
271→          status = 'streaming',
272→        } = options;
273→
274→        startTransition(() => {
275→          setMessages((prev) =>
276→            prev.map((item) => {
277→              if (item.id !== assistantMessage.id) return item;
278→              return {
279→                ...item,
280→                content: nextContent,
281→                isStreaming,
282→                isError,
283→                sources,
284→                uiActions,
285→                model,
286→                structured,
287→                guardrailNotice,
288→                guardrailDecision,
289→                guardrailMode,
290→              };
291→            })
292→          );
293→        });
294→
295→        setAssistantTurns((prev) =>
296→          updateTurnById(prev, turnId, (turn) => ({
297→            ...turn,
298→            assistantText: nextContent,
299→            status,
300→            sources,
301→            uiActions,
302→            model,
303→            structured,
304→            guardrailNotice,
305→            guardrailDecision,
306→            guardrailMode,
307→          }))
308→        );
309→      };
310→
311→      const flushBuffer = (force = false) => {
312→        const { flush, remain } = extractFlushableText(pendingBuffer, force);
313→        if (!flush && !force) return;
314→
315→        renderedContent += flush;
316→        pendingBuffer = remain;
317→
318→        if (force && pendingBuffer) {
319→          renderedContent += pendingBuffer;
320→          pendingBuffer = '';
321→        }
322→
323→        syncAssistantState(renderedContent, {
324→          isStreaming: true,
325→          status: 'streaming',
326→        });
327→      };
328→
329→      const processSseLine = (line, eventName = '') => {
330→        const trimmed = line.trim();
331→        if (!trimmed || !trimmed.startsWith('data:')) return;
332→
333→        try {
334→          const payload = trimmed.slice(5).trimStart();
335→          const data = JSON.parse(payload);
336→          const dataType = typeof data.type === 'string' ? data.type.trim() : '';
337→          const eventType = typeof eventName === 'string' ? eventName.trim() : '';
338→          const normalizedEventType = dataType || eventType;
339→
340→          if (!dataType && normalizedEventType) {
341→            data.type = normalizedEventType;
342→          }
343→
344→          if (data.session_id) {
345→            resolvedSessionId = data.session_id;
346→            setSessionId(data.session_id);
347→            try { localStorage.setItem('adelie_tutor_session', data.session_id); } catch {}
348→            if (onSessionCreated) onSessionCreated(data.session_id);
349→          }
350→
351→          if (data.type === 'thinking') {
352→            if (setAgentStatus) {
353→              setAgentStatus({ phase: 'thinking', text: data.content || '질문을 분석 중입니다.' });
354→            }
355→            return;
356→          }
357→
358→          if (data.type === 'tool_call') {
359→            if (setAgentStatus) {
360→              setAgentStatus({ phase: 'tool_call', text: `도구 실행 중: ${data.tool || '분석 도구'}`, tool: data.tool || undefined });
361→            }
362→            return;
363→          }
364→
365→          if (data.type === 'guardrail_notice') {
366→            pendingGuardrailNotice = typeof data.content === 'string' ? data.content : null;
367→            pendingGuardrailDecision = typeof data.guardrail_decision === 'string' ? data.guardrail_decision : pendingGuardrailDecision;
368→            pendingGuardrailMode = typeof data.guardrail_mode === 'string' ? data.guardrail_mode : pendingGuardrailMode;
369→            if (setAgentStatus && pendingGuardrailNotice) {
370→              setAgentStatus({ phase: 'notice', text: pendingGuardrailNotice });
371→            }
372→            syncAssistantState(renderedContent, {
373→              isStreaming: true,
374→              status: 'streaming',
375→              guardrailNotice: pendingGuardrailNotice,
376→              guardrailDecision: pendingGuardrailDecision,
377→              guardrailMode: pendingGuardrailMode,
378→            });
379→            return;
380→          }
381→
382→          if (data.type === 'sources' && Array.isArray(data.sources)) {
383→            pendingSources = data.sources;
384→            return;
385→          }
386→
387→          if (data.type === 'ui_action' && Array.isArray(data.actions)) {
388→            pendingUiActions = data.actions;
389→            syncAssistantState(renderedContent, {
390→              isStreaming: true,
391→              status: 'streaming',
392→              uiActions: pendingUiActions,
393→            });
394→            return;
395→          }
396→
397→          if (data.type === 'visualization' && (data.chartData || data.content)) {
398→            const vizMessage = {
399→              id: Date.now() + Math.random(),
400→              role: 'visualization',
401→              content: data.content || null,
402→              format: data.format || 'html',
403→              chartData: data.chartData || null,
404→              executionTime: data.execution_time_ms,
405→              timestamp: new Date().toISOString(),
406→            };
407→            setMessages((prev) => [...prev, vizMessage]);
408→            return;
409→          }
410→
411→          if (data.type === 'error' && data.error) {
412→            hasError = true;
413→            flushBuffer(true);
414→            const errorText = renderedContent || `오류: ${data.error}`;
415→            if (setAgentStatus) setAgentStatus({ phase: 'error', text: '오류가 발생했습니다.' });
416→            syncAssistantState(errorText, {
417→              isStreaming: false,
418→              isError: true,
419→              status: 'error',
420→            });
421→            return;
422→          }
423→
424→          if (data.type === 'done') {
425→            doneReceived = true;
426→            if (Array.isArray(data.sources)) {
427→              pendingSources = data.sources;
428→            }
429→            if (Array.isArray(data.actions)) {
430→              pendingUiActions = data.actions;
431→            }
432→            if (typeof data.model === 'string' && data.model.trim()) {
433→              pendingModel = data.model.trim();
434→            }
435→            if (data.structured && typeof data.structured === 'object') {
436→              pendingStructured = data.structured;
437→            }
438→            if (typeof data.guardrail_decision === 'string') {
439→              pendingGuardrailDecision = data.guardrail_decision;
440→            }
441→            if (typeof data.guardrail_mode === 'string') {
442→              pendingGuardrailMode = data.guardrail_mode;
443→            }
444→
445→            flushBuffer(true);
446→            syncAssistantState(renderedContent, {
447→              isStreaming: false,
448→              status: hasError ? 'error' : 'done',
449→            });
450→            if (setAgentStatus && !hasError) setAgentStatus(DEFAULT_STATUS);
451→            return;
452→          }
453→
454→          if (typeof data.content === 'string') {
455→            const contentType = typeof data.type === 'string' ? data.type : '';
456→            const isTextDelta = !contentType
457→              || contentType === 'text_delta'
458→              || contentType === 'response.output_text.delta'
459→              || contentType === 'message_delta';
460→            if (!isTextDelta) return;
461→
462→            const sanitized = sanitizeStreamDelta(data.content);
463→            if (!sanitized) return;
464→
465→            if (!renderedContent && setAgentStatus) {
466→              setAgentStatus({ phase: 'answering', text: '답변을 생성 중입니다.' });
467→            }
468→
469→            pendingBuffer += sanitized;
470→
471→            const now = Date.now();
472→            const shouldFlush = /[.!?。！？\n]/.test(sanitized)
473→              || (pendingBuffer.length >= 14 && now - lastFlushAt >= STREAM_FLUSH_INTERVAL_MS);
474→
475→            if (shouldFlush) {
476→              flushBuffer(false);
477→              lastFlushAt = now;
478→            }
479→          }
480→        } catch {
481→          // malformed SSE chunk 무시
482→        }
483→      };
484→
485→      // 튜터 질문 트래킹
486→      trackEvent(TRACK_EVENTS.TUTOR_ASK, { session_id: sessionId, message_length: normalizedMessage.length });
487→
488→      try {
489→        const response = await authFetch(`${API_BASE_URL}/api/v1/tutor/chat`, {
490→          method: 'POST',
491→          signal: streamController.signal,
492→          headers: { 'Content-Type': 'application/json' },
493→          body: JSON.stringify({
494→            session_id: sessionId,
495→            message: normalizedMessage,
496→            difficulty,
497→            context_type: contextInfo?.type,
498→            context_id: contextInfo?.id,
499→            context_text: contextInfo?.stepContent,
500→            use_web_search: normalizedOptions.useWebSearch,
501→            response_mode: normalizedOptions.responseMode,
502→            structured_extract: normalizedOptions.structuredExtract,
503→          }),
504→        });
505→
506→        if (!response.ok) throw new Error('Failed to get response');
507→        if (!response.body) throw new Error('Response body is empty');
508→
509→        const reader = response.body.getReader();
510→        const decoder = new TextDecoder();
511→        let streamBuffer = '';
512→        let currentEventName = '';
513→
514→        while (true) {
515→          const { done, value } = await reader.read();
516→          if (done) break;
517→
518→          streamBuffer += decoder.decode(value, { stream: true });
519→          const lines = streamBuffer.split('\n');
520→          streamBuffer = lines.pop() || '';
521→
522→          for (const line of lines) {
523→            const trimmed = line.trim();
524→            if (trimmed.startsWith('event:')) {
525→              currentEventName = trimmed.slice(6).trim();
526→              continue;
527→            }
528→
529→            processSseLine(line, currentEventName);
530→            if (!trimmed) {
531→              currentEventName = '';
532→            }
533→          }
534→        }
535→
536→        const remaining = `${streamBuffer}${decoder.decode()}`;
537→        if (remaining.trim()) {
538→          remaining.split('\n').forEach((line) => {
539→            const trimmed = line.trim();
540→            if (trimmed.startsWith('event:')) {
541→              currentEventName = trimmed.slice(6).trim();
542→              return;
543→            }
544→            processSseLine(line, currentEventName);
545→            if (!trimmed) {
546→              currentEventName = '';
547→            }
548→          });
549→        }
550→
551→        flushBuffer(true);
552→
553→        if (!doneReceived) {
554→          syncAssistantState(renderedContent, {
555→            isStreaming: false,
556→            isError: hasError,
557→            status: hasError ? 'error' : 'done',
558→          });
559→        }
560→
561→        persistSessionMeta(
562→          resolvedSessionId,
563→          contextInfo,
564→          normalizedMessage,
565→          renderedContent,
566→        );
567→      } catch (error) {
568→        if (error?.name === 'AbortError') {
569→          wasStopped = true;
570→          flushBuffer(true);
571→          if (setAgentStatus) setAgentStatus({ phase: 'stopped', text: '생성이 중단되었습니다.' });
572→          syncAssistantState(renderedContent, {
573→            isStreaming: false,
574→            isError: false,
575→            status: 'stopped',
576→          });
577→          persistSessionMeta(
578→            resolvedSessionId,
579→            contextInfo,
580→            normalizedMessage,
581→            renderedContent,
582→          );
583→          return;
584→        }
585→
586→        console.error('Tutor error:', error);
587→        hasError = true;
588→        if (setAgentStatus) setAgentStatus({ phase: 'error', text: '오류가 발생했습니다.' });
589→
590→        const fallbackText = renderedContent || '죄송합니다. 오류가 발생했습니다.';
591→        syncAssistantState(fallbackText, {
592→          isStreaming: false,
593→          isError: true,
594→          status: 'error',
595→        });
596→      } finally {
597→        if (activeStreamControllerRef.current === streamController) {
598→          activeStreamControllerRef.current = null;
599→        }
600→        setIsStreamingActive(false);
601→        setIsLoading(false);
602→        if (setAgentStatus && !hasError && !wasStopped) setAgentStatus(DEFAULT_STATUS);
603→      }
604→    },
605→    [persistSessionMeta, sessionId]
606→  );
607→
608→  const loadChatHistory = useCallback(async (id, setActiveSessionId) => {
609→    if (setActiveSessionId) setActiveSessionId(id);
610→
611→    const { fetchJson } = await import('../api/client');
612→    const data = await fetchJson(`${API_BASE_URL}/api/v1/tutor/sessions/${id}/messages`);
613→    const loaded = (data.messages || []).map((message, index) => mapHistoryMessage(message, index));
614→
615→    setMessages(loaded);
616→    setAssistantTurns(buildAssistantTurns(loaded));
617→    setSessionId(id);
618→    try { localStorage.setItem('adelie_tutor_session', id); } catch {}
619→  }, []);
620→
621→  const stopGeneration = useCallback(() => {
622→    const controller = activeStreamControllerRef.current;
623→    if (!controller) return false;
624→
625→    controller.abort();
626→    activeStreamControllerRef.current = null;
627→    setIsStreamingActive(false);
628→    return true;
629→  }, []);
630→
631→  const regenerateLastResponse = useCallback(
632→    async (setAgentStatus = null, onSessionCreated = null, overrides = {}) => {
633→      const previous = lastRequestRef.current;
634→      if (!previous?.message) return false;
635→
636→      await sendMessage(
637→        previous.message,
638→        overrides?.difficulty || previous.difficulty || 'beginner',
639→        overrides?.contextInfo || previous.contextInfo || null,
640→        setAgentStatus,
641→        onSessionCreated,
642→        overrides?.options || previous.options || {},
643→      );
644→
645→      return true;
646→    },
647→    [sendMessage],
648→  );
649→
650→  const clearMessages = useCallback(() => {
651→    if (activeStreamControllerRef.current) {
652→      activeStreamControllerRef.current.abort();
653→      activeStreamControllerRef.current = null;
654→    }
655→    setMessages((prev) => (prev.length > 0 ? [] : prev));
656→    setAssistantTurns((prev) => (prev.length > 0 ? [] : prev));
657→    setSessionId((prev) => (prev === null ? prev : null));
658→    setIsStreamingActive(false);
659→    setCanRegenerate(false);
660→    lastRequestRef.current = null;
661→    try {
662→      if (localStorage.getItem('adelie_tutor_session') !== null) {
663→        localStorage.removeItem('adelie_tutor_session');
664→      }
665→    } catch {}
666→  }, []);
667→
668→  return (
669→    <TutorChatContext.Provider value={{
670→      messages,
671→      assistantTurns,
672→      isLoading,
673→      isStreamingActive,
674→      canRegenerate,
675→      sessionId,
676→      setSessionId,
677→      sendMessage,
678→      stopGeneration,
679→      regenerateLastResponse,
680→      loadChatHistory,
681→      clearMessages,
682→    }}>
683→      {children}
684→    </TutorChatContext.Provider>
685→  );
686→}
687→
688→export function useTutorChat() {
689→  const ctx = useContext(TutorChatContext);
690→  if (!ctx) throw new Error('useTutorChat must be used within TutorChatProvider');
691→  return ctx;
692→}
