  1→import { createContext, useContext, useState, useCallback, useEffect } from 'react';
  2→import { API_BASE_URL, fetchJson, postJson, deleteJson } from '../api/client';
  3→import { removeSessionCardMeta } from '../utils/agent/sessionCardMetaStore';
  4→import { trackEvent, TRACK_EVENTS } from '../utils/analytics';
  5→
  6→const TutorSessionContext = createContext(null);
  7→
  8→const SESSION_KEY = 'adelie_tutor_session';
  9→
 10→export function TutorSessionProvider({ children }) {
 11→  const [sessions, setSessions] = useState([]);
 12→  const [activeSessionId, setActiveSessionId] = useState(() => {
 13→    try {
 14→      return localStorage.getItem(SESSION_KEY) || null;
 15→    } catch {
 16→      return null;
 17→    }
 18→  });
 19→
 20→  // 세션 복원 시 서버 유효성 검증
 21→  const validateSession = useCallback(async (sessionId) => {
 22→    try {
 23→      const res = await fetchJson(`${API_BASE_URL}/api/v1/tutor/sessions/${sessionId}`);
 24→      return !!res;
 25→    } catch {
 26→      return false;
 27→    }
 28→  }, []);
 29→
 30→  // localStorage에서 복원된 세션이 서버에 존재하는지 확인
 31→  useEffect(() => {
 32→    if (!activeSessionId) return;
 33→    validateSession(activeSessionId).then((isValid) => {
 34→      if (!isValid) {
 35→        setActiveSessionId(null);
 36→        try { localStorage.removeItem(SESSION_KEY); } catch {}
 37→      }
 38→    });
 39→  }, []); // 마운트 시 1회만 실행
 40→
 41→  const refreshSessions = useCallback(async () => {
 42→    try {
 43→      const sessionList = await fetchJson(`${API_BASE_URL}/api/v1/tutor/sessions`);
 44→      setSessions(Array.isArray(sessionList) ? sessionList : []);
 45→    } catch (error) {
 46→      console.error('세션 목록 조회 실패:', error);
 47→      setSessions([]);
 48→    }
 49→  }, []);
 50→
 51→  const createNewChat = useCallback(async (onCreated) => {
 52→    const created = await postJson(`${API_BASE_URL}/api/v1/tutor/sessions/new`, {});
 53→    const nextSessionId = created?.session_id || null;
 54→
 55→    setActiveSessionId(nextSessionId);
 56→    try {
 57→      if (nextSessionId) localStorage.setItem(SESSION_KEY, nextSessionId);
 58→      else localStorage.removeItem(SESSION_KEY);
 59→    } catch {}
 60→
 61→    // 세션 생성 트래킹
 62→    trackEvent(TRACK_EVENTS.TUTOR_SESSION_CREATE, { session_id: nextSessionId });
 63→
 64→    if (onCreated) onCreated(nextSessionId);
 65→    await refreshSessions();
 66→    return nextSessionId;
 67→  }, [refreshSessions]);
 68→
 69→  const deleteChat = useCallback(async (id, onDeleted) => {
 70→    await deleteJson(`${API_BASE_URL}/api/v1/tutor/sessions/${id}`);
 71→
 72→    // 삭제된 세션의 카드 메타(localStorage) 정리
 73→    removeSessionCardMeta(id);
 74→
 75→    if (activeSessionId === id) {
 76→      setActiveSessionId(null);
 77→      try { localStorage.removeItem(SESSION_KEY); } catch {}
 78→      if (onDeleted) onDeleted();
 79→    }
 80→
 81→    await refreshSessions();
 82→  }, [activeSessionId, refreshSessions]);
 83→
 84→  return (
 85→    <TutorSessionContext.Provider value={{
 86→      sessions,
 87→      activeSessionId,
 88→      setActiveSessionId,
 89→      refreshSessions,
 90→      createNewChat,
 91→      deleteChat,
 92→    }}>
 93→      {children}
 94→    </TutorSessionContext.Provider>
 95→  );
 96→}
 97→
 98→export function useTutorSession() {
 99→  const ctx = useContext(TutorSessionContext);
100→  if (!ctx) throw new Error('useTutorSession must be used within TutorSessionProvider');
101→  return ctx;
102→}
