 80→
 81→  return (
 82→    <AnimatePresence>
 83→      {isOpen && (
 84→        <>
 85→          <motion.div className="fixed inset-0 bg-black/50 z-40" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={closeTutor} />
 86→          <motion.div
 87→            className="fixed inset-x-0 bottom-0 bg-background rounded-t-3xl z-50 max-w-mobile mx-auto flex flex-col"
 88→            style={{ height: '85vh' }}
 89→            initial={{ y: '100%' }} animate={{ y: 0 }} exit={{ y: '100%' }}
 90→            transition={{ type: 'spring', damping: 25, stiffness: 300 }}
 91→          >
 92→            {/* Header */}
 93→            <div className="border-b border-border">
 94→              <div className="flex items-center justify-between p-4">
 95→                <div className="flex items-center gap-2">
 96→                  <img src="/images/penguin-3d.png" alt="AI Tutor" className="w-8 h-8" />
 97→                  <div>
 98→                    <h2 className="font-bold text-text-primary">AI 튜터와 대화</h2>
 99→                    <p className="text-xs text-text-secondary capitalize">{settings.difficulty} 모드</p>
100→                  </div>
101→                </div>
102→                <div className="flex items-center gap-2">
103→                  <button onClick={handleNewChat} className="px-3 py-1.5 text-sm bg-primary text-white rounded-lg hover:bg-primary-hover transition-colors">새 대화</button>
104→                  <button onClick={() => setIsSessionsOpen((prev) => !prev)} className="px-3 py-1.5 text-sm bg-surface text-text-primary border border-border rounded-lg hover:bg-surface-elevated transition-colors">대화 목록</button>
105→                  <button onClick={closeTutor} className="p-2 rounded-lg hover:bg-surface transition-colors text-text-secondary">✕</button>
106→                </div>
