129→                  </div>
130→                </div>
131→              ) : (
132→                <>
133→                  {messages.map((m) => <Message key={m.id} message={m} onActionClick={handleActionClick} />)}
134→                  {isLoading && messages.length > 0 && messages[messages.length - 1]?.role === 'user' && <TypingIndicator />}
135→                  <div ref={messagesEndRef} />
136→                </>
