  1→/**
  2→ * TutorPanel.jsx - AI Tutor 슬라이드 챗봇 패널
  3→ * 화면 하단에서 슬라이드 업되는 챗봇 패널
  4→ */
  5→import { useState, useEffect, useRef } from 'react';
  6→import { useTutor } from '../../contexts/TutorContext';
  7→
  8→export default function TutorPanel() {
  9→  const { isOpen, closeTutor, currentTerm } = useTutor();
 10→  const [messages, setMessages] = useState([]);
 11→  const [input, setInput] = useState('');
 12→  const [isLoading, setIsLoading] = useState(false);
 13→  const messagesEndRef = useRef(null);
 14→
 15→  useEffect(() => {
 16→    if (currentTerm && isOpen) {
 17→      setInput(`'${currentTerm}'이 뭔가요?`);
 18→      // Auto-submit the question
 19→      handleSubmit(null, `'${currentTerm}'이 뭔가요?`);
 20→    }
 21→  }, [currentTerm, isOpen]);
 22→
 23→  useEffect(() => {
 24→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
 25→  }, [messages]);
 26→
 27→  const handleSubmit = async (e, autoQuestion = null) => {
 28→    if (e) e.preventDefault();
 29→    const question = autoQuestion || input.trim();
 30→    if (!question || isLoading) return;
 31→
 32→    setMessages(prev => [...prev, { role: 'user', content: question }]);
 33→    setInput('');
 34→    setIsLoading(true);
 35→
 36→    try {
 37→      // Call the term explanation API
 38→      const response = await fetch(`/api/v1/tutor/explain/${encodeURIComponent(currentTerm || question)}?difficulty=beginner`);
 39→      const data = await response.json();
 40→
 41→      setMessages(prev => [...prev, {
 42→        role: 'assistant',
 43→        content: data.explanation || '죄송합니다. 설명을 가져오는데 실패했습니다.',
 44→      }]);
 45→    } catch (error) {
 46→      setMessages(prev => [...prev, {
 47→        role: 'assistant',
 48→        content: '오류가 발생했습니다. 다시 시도해주세요.',
 49→      }]);
 50→    } finally {
 51→      setIsLoading(false);
 52→    }
 53→  };
 54→
 55→  if (!isOpen) return null;
 56→
 57→  return (
 58→    <div className="tutor-panel tutor-panel-open">
 59→      {/* Header */}
 60→      <div className="flex items-center justify-between p-4 border-b border-border">
 61→        <div className="flex items-center gap-2">
 62→          <span className="text-2xl">📚</span>
 63→          <h3 className="font-semibold">AI Tutor</h3>
 64→        </div>
 65→        <button
 66→          onClick={closeTutor}
 67→          className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-surface"
 68→        >
 69→          ✕
 70→        </button>
 71→      </div>
 72→
 73→      {/* Messages */}
 74→      <div className="flex-1 overflow-y-auto p-4 space-y-4" style={{ maxHeight: 'calc(70vh - 140px)' }}>
 75→        {messages.length === 0 && (
 76→          <div className="text-center text-secondary py-8">
 77→            <p>궁금한 용어에 대해 물어보세요!</p>
 78→          </div>
 79→        )}
 80→        {messages.map((msg, index) => (
 81→          <div
 82→            key={index}
 83→            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
 84→          >
 85→            <div
 86→              className={`max-w-[80%] p-3 rounded-2xl ${
 87→                msg.role === 'user'
 88→                  ? 'bg-primary text-white rounded-br-md'
 89→                  : 'bg-surface rounded-bl-md'
 90→              }`}
 91→            >
 92→              {msg.content}
 93→            </div>
 94→          </div>
 95→        ))}
 96→        {isLoading && (
 97→          <div className="flex justify-start">
 98→            <div className="bg-surface p-3 rounded-2xl rounded-bl-md">
 99→              <span className="animate-pulse">생각 중...</span>
100→            </div>
101→          </div>
102→        )}
103→        <div ref={messagesEndRef} />
104→      </div>
105→
106→      {/* Input */}
107→      <form onSubmit={handleSubmit} className="p-4 border-t border-border">
108→        <div className="flex gap-2">
109→          <input
110→            id="tutor-panel-input"
111→            name="message"
112→            type="text"
113→            value={input}
114→            onChange={(e) => setInput(e.target.value)}
115→            placeholder="용어에 대해 질문하세요..."
116→            aria-label="용어 질문 입력"
117→            className="input flex-1"
118→            disabled={isLoading}
119→          />
120→          <button
121→            type="submit"
122→            disabled={isLoading || !input.trim()}
123→            className="btn-primary px-4"
124→          >
125→            전송
126→          </button>
127→        </div>
128→      </form>
129→    </div>
130→  );
131→}
