 5→
 6→import { authFetch, fetchJson, postJson } from './client';
 7→
 8→/**
 9→ * Canvas 분석 SSE 스트리밍 요청
10→ * @param {Object} payload - CanvasAnalyzeRequest
11→ * @param {AbortSignal} [signal] - AbortController signal
12→ * @returns {Promise<Response>} SSE Response (body is ReadableStream)
13→ */
14→export async function analyzeCanvas(payload, signal) {
15→  return authFetch('/api/v1/canvas/analyze', {
16→    method: 'POST',
17→    headers: { 'Content-Type': 'application/json' },
18→    body: JSON.stringify(payload),
19→    signal,
20→  });
21→}
22→
23→/**
24→ * 사전 연산된 Canvas 데이터 조회
25→ * @param {string} [mode='home']
26→ * @param {string} [date] - YYYY-MM-DD
27→ * @returns {Promise<Object>} CanvasPrecomputedResponse
28→ */
29→export async function getPrecomputed(mode = 'home', date) {
30→  const params = new URLSearchParams({ mode });
31→  if (date) params.set('date', date);
32→  return fetchJson(`/api/v1/canvas/precomputed?${params}`);
33→}
34→
35→/**
36→ * Quick QA — 드래그 선택 즉석 설명
37→ * @param {Object} payload - { selected_text, canvas_context_summary?, session_id? }
38→ * @returns {Promise<Object>} QuickQAResponse
39→ */
40→export async function quickQA(payload) {
41→  return postJson('/api/v1/canvas/quick-qa', payload);
42→}
43→
44→/**
45→ * CTA 피드백 전송 (fire-and-forget)
46→ * @param {Object} payload - CTAFeedbackRequest
47→ */
48→export function sendCTAFeedback(payload) {
49→  const url = '/api/v1/canvas/cta-feedback';
50→  // sendBeacon for unload, fetch otherwise
51→  if (navigator.sendBeacon && payload.action === 'ignored') {
52→    navigator.sendBeacon(
53→      url,
54→      new Blob([JSON.stringify(payload)], { type: 'application/json' }),
55→    );
56→  } else {
57→    postJson(url, payload).catch(() => {});
58→  }
59→}
