 32→function buildReviewTarget(mode, contextPayload) {
 33→  if (mode === 'home') {
 34→    const dateRaw = String(contextPayload?.date || '').replace(/\D/g, '');
 35→    const dateValue = Number(dateRaw);
 36→    if (dateRaw.length === 8 && Number.isFinite(dateValue)) {
 37→      return {
 38→        contentType: 'briefing',
 39→        contentId: dateValue,
 40→      };
 41→    }
 42→    return null;
 43→  }
 44→
 45→  const caseId = Number(contextPayload?.case_id || 0);
 46→  if (Number.isInteger(caseId) && caseId > 0) {
 47→    return {
 48→      contentType: 'case',
 49→      contentId: caseId,
 50→    };
 51→  }
 52→  return null;
 53→}
