 55→function getContextByMode(mode) {
 56→  try {
 57→    if (mode === 'home') {
 58→      const enriched = sessionStorage.getItem('adelie_home_context_enriched');
 59→      if (enriched) return JSON.parse(enriched);
 60→
 61→      const base = sessionStorage.getItem('adelie_home_context');
 62→      return base ? JSON.parse(base) : null;
 63→    }
 64→
 65→    if (mode === 'education') {
 66→      const education = sessionStorage.getItem('adelie_education_context');
 67→      return education ? JSON.parse(education) : null;
 68→    }
 69→  } catch {
 70→    // ignore storage parsing error
 71→  }
