 76→function getVisibleSectionsByMode(mode) {
 77→  if (mode === 'stock') return ['portfolio_summary', 'holdings', 'stock_detail'];
 78→  if (mode === 'education') return ['calendar', 'daily_briefing', 'quiz_mission'];
