 2→ * Canvas 사전 연산 데이터 fetching 훅
 3→ * 진입 시 Redis 캐시된 분석 데이터를 먼저 시도합니다.
 4→ */
 5→
 6→import { useCallback, useEffect, useRef, useState } from 'react';
 7→import { getPrecomputed } from '../api/canvas';
 8→
 9→/**
10→ * @param {string} mode - 'home' | 'stock' | 'education'
11→ * @param {Object} [options]
12→ * @param {boolean} [options.enabled=true]
13→ * @param {string} [options.date]
14→ */
15→export default function useCanvasPrecompute(mode = 'home', { enabled = true, date } = {}) {
16→  const [data, setData] = useState(null);
17→  const [isLoading, setIsLoading] = useState(false);
18→  const [isCached, setIsCached] = useState(false);
19→  const fetchedRef = useRef(false);
20→
21→  const fetch = useCallback(async () => {
22→    if (!enabled) return null;
23→    setIsLoading(true);
24→    try {
25→      const result = await getPrecomputed(mode, date);
26→      setData(result);
27→      setIsCached(result?.cached === true);
28→      return result;
29→    } catch {
30→      setData(null);
31→      setIsCached(false);
32→      return null;
33→    } finally {
34→      setIsLoading(false);
35→    }
36→  }, [mode, date, enabled]);
37→
38→  useEffect(() => {
39→    if (enabled && !fetchedRef.current) {
40→      fetchedRef.current = true;
41→      fetch();
42→    }
43→  }, [enabled, fetch]);
44→
45→  const refresh = useCallback(() => {
46→    fetchedRef.current = false;
47→    return fetch();
48→  }, [fetch]);
49→
50→  return {
51→    data,
52→    isLoading,
53→    isCached,
54→    refresh,
55→  };
56→}
