 32→function normalizeMathDelimiters(content) {
 33→  if (!content) return '';
 34→
 35→  let normalized = String(content).replace(/\r\n/g, '\n');
 36→
 37→  // MathJax 스타일 블록 수식(\[...\])을 KaTeX 호환 블록($$...$$)으로 정규화
 38→  normalized = normalized.replace(
 39→    /(?:^|\n)\s*\\\[\s*([\s\S]*?)\s*\\?\]\s*(?=\n|$)/g,
 40→    (_, expr) => `\n$$\n${expr.trim()}\n$$\n`,
 41→  );
 42→
 43→  // MathJax 스타일 인라인 수식(\(...\))을 KaTeX 호환 인라인($...$)으로 정규화
 44→  normalized = normalized.replace(/\\\(\s*([\s\S]*?)\s*\\\)/g, (_, expr) => `$${expr.trim()}$`);
 45→
 46→  return normalized;
 47→}
