 2→ * ChatInput - 메시지 입력 폼 (슬래시 커맨드 지원)
 3→ */
 4→import { forwardRef, useState } from 'react';
 5→import SlashCommandMenu, { SLASH_COMMANDS } from '../agent/SlashCommandMenu';
 6→
 7→const ChatInput = forwardRef(function ChatInput({ value, onChange, onSubmit, isLoading }, ref) {
 8→  const [showSlashMenu, setShowSlashMenu] = useState(false);
 9→  const [slashQuery, setSlashQuery] = useState('');
10→
11→  const handleChange = (val) => {
12→    onChange(val);
13→    if (val.startsWith('/')) {
14→      setShowSlashMenu(true);
15→      setSlashQuery(val.slice(1));
16→    } else {
17→      setShowSlashMenu(false);
18→      setSlashQuery('');
19→    }
20→  };
21→
22→  const handleSlashSelect = (command) => {
23→    setShowSlashMenu(false);
24→    setSlashQuery('');
25→
26→    const action = command.action;
27→    if (action.type === 'param') {
28→      // param 타입: prefix가 있으면 입력창에 설정, 없으면 커맨드 설명을 프롬프트로 사용
29→      onChange(action.prefix || `${command.desc}: `);
30→    } else {
31→      // navigate/action 타입: 커맨드 설명을 프롬프트 텍스트로 설정
32→      onChange(`${command.desc} `);
33→    }
34→  };
35→
36→  return (
37→    <form onSubmit={onSubmit} className="relative p-4 border-t border-border bg-background">
38→      {showSlashMenu && (
39→        <SlashCommandMenu
40→          query={slashQuery}
41→          onSelect={handleSlashSelect}
42→          onClose={() => { setShowSlashMenu(false); setSlashQuery(''); }}
43→          visible={showSlashMenu}
44→        />
45→      )}
46→      <div className="flex gap-2">
47→        <input
48→          ref={ref}
49→          id="tutor-chat-input"
50→          name="message"
51→          type="text"
52→          value={value}
53→          onChange={(e) => handleChange(e.target.value)}
54→          onKeyDown={(e) => {
55→            if (showSlashMenu && (e.key === 'ArrowUp' || e.key === 'ArrowDown' || e.key === 'Enter')) {
56→              e.preventDefault();
57→            }
58→            if (e.key === 'Escape' && showSlashMenu) {
59→              setShowSlashMenu(false);
60→              setSlashQuery('');
61→            }
62→          }}
63→          placeholder="질문을 입력하세요..."
64→          aria-label="질문 입력"
65→          className="flex-1 px-4 py-3 rounded-xl border border-border bg-background text-text-primary placeholder:text-text-secondary focus:outline-none focus:border-primary"
66→          disabled={isLoading}
67→        />
68→        <button
69→          type="submit"
70→          disabled={!value.trim() || isLoading}
71→          className="px-4 py-3 bg-primary text-white rounded-xl font-medium hover:bg-primary-hover transition-colors disabled:bg-border disabled:text-text-secondary"
72→        >
73→          {isLoading ? (
74→            <span className="inline-block w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
75→          ) : '전송'}
76→        </button>
77→      </div>
78→    </form>
79→  );
80→});
81→
82→export default ChatInput;
