  9→const parseVisualizationPayload = (content) => {
 10→  if (!content) return null;
 11→  if (typeof content === 'object') return content;
 12→  try {
 13→    return JSON.parse(content);
 14→  } catch {
 15→    return null;
 16→  }
 17→};
 18→
 19→function sanitizeStreamDelta(delta) {
 20→  if (typeof delta !== 'string') return '';
 21→
 22→  const cleaned = delta
 23→    .replace(/<\|[^>]+\|>/g, '')
 24→    .replace(/\r/g, '')
 25→    .replace(/\u0000/g, '');
 26→
 27→  const trimmed = cleaned.trim();
 28→  if (!trimmed) return cleaned;
 29→
 30→  if (/^```(?:\w+)?$/i.test(trimmed)) return '';
 31→  if (/^\|{1,5}$/.test(trimmed)) return '';
 32→  if (/^\|\s*$/.test(trimmed)) return '';
 33→  if (/^(assistant|user|system)\s*[:|]$/i.test(trimmed)) return '';
 34→
 35→  return cleaned;
 36→}
 37→
 38→function extractFlushableText(buffer, force = false) {
 39→  if (!buffer) return { flush: '', remain: '' };
 40→  if (force) return { flush: buffer, remain: '' };
 41→
 42→  let boundary = -1;
 43→  for (let idx = 0; idx < buffer.length; idx += 1) {
 44→    const char = buffer[idx];
 45→    if (char === '\n' || char === '.' || char === '!' || char === '?' || char === '。' || char === '！' || char === '？') {
 46→      boundary = idx + 1;
 47→    }
 48→  }
 49→
 50→  if (boundary === -1) {
 51→    if (buffer.length < 64) return { flush: '', remain: buffer };
 52→
 53→    const whitespace = buffer.lastIndexOf(' ', 56);
 54→    boundary = whitespace > 16 ? whitespace + 1 : 56;
 55→  }
 56→
 57→  return {
 58→    flush: buffer.slice(0, boundary),
 59→    remain: buffer.slice(boundary),
 60→  };
 61→}
 62→
 63→const mapHistoryMessage = (message, index) => {
 64→  if (message.message_type === 'visualization') {
 65→    const parsed = parseVisualizationPayload(message.content);
 66→    return {
 67→      id: `${message.id || Date.now()}-viz-${index}`,
 68→      role: 'visualization',
 69→      content: parsed?.html || parsed?.content || message.chart_url || message.content || null,
 70→      format: parsed?.chartData ? 'json' : (parsed?.format || 'html'),
 71→      chartData: parsed?.chartData || null,
 72→      executionTime: message.execution_time_ms || parsed?.execution_time_ms,
 73→      timestamp: message.created_at,
 74→      isStreaming: false,
 75→    };
 76→  }
 77→
 78→  return {
 79→    id: `${message.id || Date.now()}-${index}`,
 80→    role: message.role,
 81→    content: message.content,
 82→    timestamp: message.created_at,
 83→    isStreaming: false,
 84→    sources: message.sources || null,
 85→    uiActions: message.ui_actions || null,
 86→    model: message.model || null,
 87→    structured: message.structured || null,
 88→    guardrailNotice: message.guardrail_notice || null,
 89→    guardrailDecision: message.guardrail_decision || null,
 90→    guardrailMode: message.guardrail_mode || null,
 91→  };
 92→};
 93→
 94→function buildAssistantTurns(messages = []) {
 95→  let latestUserPrompt = '';
 96→  const turns = [];
 97→
 98→  messages.forEach((message, index) => {
 99→    if (message?.role === 'user') {
100→      latestUserPrompt = typeof message.content === 'string' ? message.content : '';
101→      return;
102→    }
103→
104→    if (message?.role !== 'assistant') return;
105→
106→    turns.push({
107→      id: message.turnId || `turn-${message.id || index}`,
108→      assistantMessageId: message.id,
109→      userPrompt: latestUserPrompt,
110→      assistantText: typeof message.content === 'string' ? message.content : '',
111→      status: 'done',
112→      createdAt: message.timestamp || new Date().toISOString(),
113→      sources: Array.isArray(message.sources) ? message.sources : [],
114→      uiActions: Array.isArray(message.uiActions) ? message.uiActions : [],
115→      model: message.model || null,
116→      structured: message.structured || null,
117→      guardrailNotice: message.guardrailNotice || null,
118→      guardrailDecision: message.guardrailDecision || null,
119→      guardrailMode: message.guardrailMode || null,
120→    });
121→  });
122→
123→  return turns;
124→}
125→
126→function updateTurnById(previousTurns, turnId, updater) {
127→  return previousTurns.map((turn) => {
128→    if (turn.id !== turnId) return turn;
129→    return updater(turn);
130→  });
131→}
