133→export function TutorChatProvider({ children }) {
134→  const [messages, setMessages] = useState([]);
135→  const [assistantTurns, setAssistantTurns] = useState([]);
136→  const [isLoading, setIsLoading] = useState(false);
137→  const [isStreamingActive, setIsStreamingActive] = useState(false);
138→  const [canRegenerate, setCanRegenerate] = useState(false);
139→  const [sessionId, setSessionId] = useState(() => {
140→    try {
141→      return localStorage.getItem('adelie_tutor_session') || null;
142→    } catch {
143→      return null;
144→    }
145→  });
146→  const activeStreamControllerRef = useRef(null);
147→  const lastRequestRef = useRef(null);
148→
149→  const persistSessionMeta = useCallback((targetSessionId, contextInfo, userPrompt, assistantText) => {
150→    const normalizedSessionId = String(targetSessionId || '').trim();
151→    if (!normalizedSessionId) return;
152→
153→    const normalizedSnippet = String(assistantText || '')
154→      .replace(/\s+/g, ' ')
155→      .trim()
156→      .slice(0, 180);
157→    const fallbackTitle = String(userPrompt || '').trim().slice(0, 40) || '대화 정리 카드';
158→    const nextMeta = buildSessionCardMeta({
159→      contextInfo,
160→      fallbackTitle,
161→      fallbackSnippet: normalizedSnippet,
162→    });
163→
164→    writeSessionCardMeta(normalizedSessionId, nextMeta);
165→  }, []);
166→
167→  const sendMessage = useCallback(
168→    async (
169→      message,
170→      difficulty = 'beginner',
171→      contextInfo = null,
172→      setAgentStatus = null,
173→      onSessionCreated = null,
174→      options = {},
175→    ) => {
176→      const normalizedMessage = String(message || '').trim();
177→      if (!normalizedMessage) return;
178→
179→      if (activeStreamControllerRef.current) {
180→        activeStreamControllerRef.current.abort();
181→        activeStreamControllerRef.current = null;
182→      }
183→
184→      const DEFAULT_STATUS = { phase: 'idle', text: '응답 대기 중' };
185→      let hasError = false;
186→      let wasStopped = false;
187→      let pendingSources = [];
188→      let pendingUiActions = [];
189→      let pendingModel = null;
190→      let pendingStructured = null;
191→      let pendingGuardrailNotice = null;
192→      let pendingGuardrailDecision = null;
193→      let pendingGuardrailMode = null;
194→      let pendingBuffer = '';
195→      let renderedContent = '';
196→      let lastFlushAt = Date.now();
197→      let doneReceived = false;
198→      const normalizedOptions = {
199→        useWebSearch: Boolean(options?.useWebSearch),
200→        responseMode: options?.responseMode || 'plain',
201→        structuredExtract: Boolean(options?.structuredExtract),
202→      };
203→      let resolvedSessionId = sessionId;
204→      const streamController = new AbortController();
205→      activeStreamControllerRef.current = streamController;
206→      setIsStreamingActive(true);
207→      setCanRegenerate(true);
208→      lastRequestRef.current = {
209→        message: normalizedMessage,
210→        difficulty,
211→        contextInfo,
212→        options: normalizedOptions,
213→      };
214→
215→      const turnId = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
216→
217→      const userMessage = {
218→        id: `${Date.now()}-user`,
219→        turnId,
220→        role: 'user',
221→        content: normalizedMessage,
222→        timestamp: new Date().toISOString(),
223→      };
224→      setMessages((prev) => [...prev, userMessage]);
225→      setIsLoading(true);
226→      if (setAgentStatus) setAgentStatus({ phase: 'thinking', text: '질문을 분석 중입니다.' });
227→
228→      const assistantMessage = {
229→        id: `${Date.now()}-assistant`,
230→        turnId,
231→        role: 'assistant',
232→        content: '',
233→        timestamp: new Date().toISOString(),
234→        isStreaming: true,
235→        structured: null,
236→        guardrailNotice: null,
237→        guardrailDecision: null,
238→        guardrailMode: null,
239→      };
240→      setMessages((prev) => [...prev, assistantMessage]);
241→      setAssistantTurns((prev) => [
242→        ...prev,
243→        {
244→          id: turnId,
245→          assistantMessageId: assistantMessage.id,
246→          userPrompt: normalizedMessage,
247→          assistantText: '',
248→          status: 'streaming',
249→          createdAt: assistantMessage.timestamp,
250→          sources: [],
251→          uiActions: [],
252→          model: null,
253→          structured: null,
254→          guardrailNotice: null,
255→          guardrailDecision: null,
256→          guardrailMode: null,
257→        },
258→      ]);
259→
260→      const syncAssistantState = (nextContent, options = {}) => {
261→        const {
262→          isStreaming = true,
263→          isError = false,
264→          sources = pendingSources,
265→          uiActions = pendingUiActions,
266→          model = pendingModel,
267→          structured = pendingStructured,
268→          guardrailNotice = pendingGuardrailNotice,
269→          guardrailDecision = pendingGuardrailDecision,
270→          guardrailMode = pendingGuardrailMode,
271→          status = 'streaming',
272→        } = options;
273→
274→        startTransition(() => {
275→          setMessages((prev) =>
276→            prev.map((item) => {
277→              if (item.id !== assistantMessage.id) return item;
278→              return {
279→                ...item,
280→                content: nextContent,
281→                isStreaming,
282→                isError,
283→                sources,
284→                uiActions,
285→                model,
286→                structured,
287→                guardrailNotice,
288→                guardrailDecision,
289→                guardrailMode,
290→              };
291→            })
292→          );
293→        });
294→
295→        setAssistantTurns((prev) =>
296→          updateTurnById(prev, turnId, (turn) => ({
297→            ...turn,
298→            assistantText: nextContent,
299→            status,
300→            sources,
301→            uiActions,
302→            model,
303→            structured,
304→            guardrailNotice,
305→            guardrailDecision,
306→            guardrailMode,
307→          }))
308→        );
309→      };
310→
311→      const flushBuffer = (force = false) => {
312→        const { flush, remain } = extractFlushableText(pendingBuffer, force);
313→        if (!flush && !force) return;
314→
315→        renderedContent += flush;
316→        pendingBuffer = remain;
317→
318→        if (force && pendingBuffer) {
319→          renderedContent += pendingBuffer;
320→          pendingBuffer = '';
321→        }
322→
323→        syncAssistantState(renderedContent, {
324→          isStreaming: true,
325→          status: 'streaming',
326→        });
327→      };
328→
329→      const processSseLine = (line, eventName = '') => {
330→        const trimmed = line.trim();
331→        if (!trimmed || !trimmed.startsWith('data:')) return;
332→
333→        try {
334→          const payload = trimmed.slice(5).trimStart();
335→          const data = JSON.parse(payload);
336→          const dataType = typeof data.type === 'string' ? data.type.trim() : '';
337→          const eventType = typeof eventName === 'string' ? eventName.trim() : '';
338→          const normalizedEventType = dataType || eventType;
339→
340→          if (!dataType && normalizedEventType) {
341→            data.type = normalizedEventType;
342→          }
343→
344→          if (data.session_id) {
