 49→  const [showSlashMenu, setShowSlashMenu] = useState(false);
 50→  const [slashQuery, setSlashQuery] = useState('');
 51→  const [activePrefix, setActivePrefix] = useState(null);
 52→  const location = useLocation();
 53→  const navigate = useNavigate();
 54→  const { messages, agentStatus, isStreamingActive } = useTutor();
 55→  const { openTutor } = useTutorUI();
 56→  const { keyboardOffset, shouldHideBottomNav } = useKeyboardInset();
 57→  const hasActiveSession = Array.isArray(messages) && messages.length > 0;
 58→  const isAgentRoute = location.pathname.startsWith('/agent');
 59→  const hideBottomNav = shouldHideBottomNav;
 60→
 61→  useEffect(() => {
 62→    try {
 63→      localStorage.setItem(SEARCH_TOGGLE_KEY, searchEnabled ? '1' : '0');
 64→    } catch {
 65→      // ignore storage errors
 66→    }
 67→  }, [searchEnabled]);
 68→
 69→  useEffect(() => {
 70→    try {
 71→      const hasStoredValue = localStorage.getItem(SEARCH_TOGGLE_KEY);
 72→      if (hasStoredValue === null) {
 73→        setSearchEnabled(mode === 'stock');
 74→      }
 75→    } catch {
 76→      setSearchEnabled(mode === 'stock');
 77→    }
 78→  }, [mode]);
 79→
 80→  useEffect(() => {
 81→    document.documentElement.style.setProperty('--keyboard-offset', `${keyboardOffset}px`);
 82→    return () => {
 83→      document.documentElement.style.setProperty('--keyboard-offset', '0px');
 84→    };
 85→  }, [keyboardOffset]);
 86→
 87→  const baseContextPayload = useMemo(() => {
 88→    if (mode === 'stock' && location.state?.stockContext) {
 89→      return location.state.stockContext;
 90→    }
 91→
 92→    if (mode === 'home') {
 93→      return readSessionJson('adelie_home_context');
 94→    }
 95→
 96→    if (mode === 'education') {
 97→      return readSessionJson('adelie_education_context');
 98→    }
 99→
100→    return null;
101→  }, [location.state, mode]);
102→
103→  const {
104→    controlState,
105→    isAgentControlling,
106→    actionCatalog: orchestratorActionCatalog,
107→    executeAction,
108→    pendingAction,
109→    confirmPendingAction,
110→  } = useAgentControlOrchestrator({
111→    mode,
112→    stockContext: baseContextPayload,
113→  });
114→
115→  const actionCatalog = useMemo(
116→    () => buildActionCatalog({ pathname: location.pathname, mode, stockContext: baseContextPayload }),
117→    [baseContextPayload, location.pathname, mode],
118→  );
119→
120→  const buildControlContextPayload = useCallback((prompt = '') => {
121→    const uiSnapshot = buildUiSnapshot({
122→      pathname: location.pathname,
123→      mode,
124→      locationState: location.state || null,
125→      visibleSections: getVisibleSectionsByMode(mode),
126→      selectedEntities: {
127→        stock_code: baseContextPayload?.stock_code || null,
128→        stock_name: baseContextPayload?.stock_name || null,
129→        date_key: baseContextPayload?.date || null,
130→        case_id: baseContextPayload?.case_id || null,
131→      },
132→      filters: {
133→        tab: location.pathname.startsWith('/portfolio') ? 'portfolio' : mode,
134→      },
135→      portfolioSummary: baseContextPayload?.portfolio_summary || null,
136→    });
137→
138→    return {
139→      ...(baseContextPayload || {}),
140→      ui_snapshot: uiSnapshot,
141→      action_catalog: actionCatalog,
142→      interaction_state: {
143→        source: 'agent_dock',
144→        mode,
145→        route: location.pathname,
146→        last_prompt: prompt || null,
147→        search_enabled: searchEnabled,
148→        control_phase: controlState.phase,
149→        control_active: isAgentControlling,
150→      },
151→    };
152→  }, [actionCatalog, baseContextPayload, controlState.phase, isAgentControlling, location.pathname, location.state, mode, searchEnabled]);
153→
154→  const handleSlashCommand = useCallback((command) => {
155→    setShowSlashMenu(false);
156→    setSlashQuery('');
157→
158→    const action = command.action;
159→    if (action.type === 'navigate') {
160→      navigate(action.path, action.tab ? { state: { tab: action.tab } } : undefined);
161→    } else if (action.type === 'action') {
162→      const matchedAction = orchestratorActionCatalog.find((item) => item.id === action.actionId);
163→      if (matchedAction) {
164→        executeAction(matchedAction, { contextPayload: buildControlContextPayload('') });
165→      } else {
166→        setInlineMessage({ text: '현재 화면에서 사용할 수 없는 명령이에요.', canvasPrompt: null });
167→      }
168→    } else if (action.type === 'param') {
169→      if (action.prefix) {
170→        setActivePrefix({ label: command.desc, prefix: action.prefix });
171→        setInput('');
172→      }
173→      if (action.key === 'use_web_search') {
174→        setSearchEnabled(true);
175→      }
176→    }
177→  }, [navigate, orchestratorActionCatalog, executeAction, buildControlContextPayload]);
178→
179→  const submitPromptToCanvas = useCallback((prompt) => {
180→    const payload = buildControlContextPayload(prompt);
181→
182→    navigate('/agent', {
183→      state: {
184→        mode,
185→        initialPrompt: prompt.trim(),
186→        contextPayload: payload,
187→        useWebSearch: searchEnabled,
188→        resetConversation: location.pathname !== '/agent',
189→      },
190→    });
191→  }, [buildControlContextPayload, location.pathname, mode, navigate, searchEnabled]);
192→
193→  const routePrompt = useCallback(async (prompt, payload) => {
194→    const response = await authFetch(`${API_BASE_URL}/api/v1/tutor/route`, {
195→      method: 'POST',
196→      headers: { 'Content-Type': 'application/json' },
197→      body: JSON.stringify({
198→        message: prompt,
199→        mode,
200→        context_text: JSON.stringify(payload),
201→        ui_snapshot: payload.ui_snapshot || null,
202→        action_catalog: payload.action_catalog || [],
203→        interaction_state: payload.interaction_state || null,
204→      }),
205→    });
206→    if (!response.ok) {
207→      throw new Error('route_failed');
208→    }
209→    return response.json();
210→  }, [mode]);
211→
212→  if (shouldHide) return null;
213→
214→  const phaseTextByPhase = {
215→    thinking: '에이전트 분석 중',
216→    tool_call: '도구 실행 중',
217→    answering: '답변 생성 중',
218→    stopped: '중단됨',
219→    notice: '답변 생성 중',
220→    error: '오류 발생',
221→    idle: '대기 중',
222→  };
223→  const isActivelyWorking = isStreamingActive || isAgentRoute;
224→  const dockStatusText = isAgentRoute
225→    ? (phaseTextByPhase[agentStatus?.phase] || phaseTextByPhase.idle)
226→    : '질문하세요';
227→  const shouldShowChevron = hasActiveSession && !isAgentRoute;
228→  const pulseActive = isRouting || isAgentControlling || isStreamingActive;
229→  const statusDotClass = pulseActive ? 'agent-status-dot-pulse' : '';
230→
231→  const submitPrompt = async (prompt) => {
232→    const raw = String(prompt || '').trim();
233→    const normalized = activePrefix ? `${activePrefix.prefix}${raw}` : raw;
234→    if (!normalized) return;
235→
236→    const controlPayload = buildControlContextPayload(normalized);
237→    setIsRouting(true);
238→    setInlineMessage(null);
239→
240→    try {
241→      const decision = await routePrompt(normalized, controlPayload);
242→      const nextDecision = decision?.decision;
243→
244→      if (nextDecision === 'inline_action') {
245→        const matchedAction = orchestratorActionCatalog.find((item) => item.id === decision?.action_id);
246→        if (!matchedAction) {
247→          setInlineMessage({
248→            text: '실행 가능한 액션을 찾지 못했어요.',
249→            canvasPrompt: normalized,
250→          });
251→        } else {
252→          await executeAction(matchedAction, {
253→            contextPayload: controlPayload,
254→            prompt: normalized,
255→          });
256→        }
257→      } else if (nextDecision === 'open_canvas') {
258→        submitPromptToCanvas(decision?.canvas_prompt || normalized);
259→      } else if (nextDecision === 'open_chat') {
260→        openTutor(decision?.canvas_prompt || normalized);
261→      } else {
262→        setInlineMessage({
263→          text: decision?.inline_text || '자세히 보려면 캔버스를 열어주세요.',
264→          canvasPrompt: decision?.canvas_prompt || normalized,
265→        });
266→      }
267→    } catch {
268→      setInlineMessage({
269→        text: '자세한 분석은 캔버스에서 확인할 수 있어요.',
270→        canvasPrompt: normalized,
271→      });
272→    } finally {
273→      setIsRouting(false);
274→    }
275→
276→    setInput('');
277→    setActivePrefix(null);
278→  };
279→
280→  const handleSubmit = async (event) => {
281→    event.preventDefault();
282→    await submitPrompt(input || suggestedPrompt);
283→  };
284→
285→  const handleResumeChat = () => {
286→    navigate('/agent', {
287→      state: {
288→        mode,
289→        contextPayload: buildControlContextPayload(''),
290→        useWebSearch: searchEnabled,
291→      },
292→    });
293→  };
294→
295→  return (
296→    <div
297→      className="pointer-events-none fixed left-0 right-0 z-30 flex justify-center px-4 pb-2"
298→      style={{ bottom: `calc(${hideBottomNav ? '0px' : 'var(--bottom-nav-h,68px)'} + var(--keyboard-offset,0px))` }}
299→    >
300→      <div className="w-full max-w-mobile space-y-1.5">
301→        {/* 인라인 메시지 (트레이 대체 — 필요할 때만 노출) */}
302→        {inlineMessage?.text && (
303→          <div className="pointer-events-auto flex items-center justify-between gap-2 rounded-[14px] border border-[var(--agent-border,#E8EBED)] bg-white px-3 py-2 shadow-[var(--agent-shadow)]">
304→            <p className="min-w-0 truncate text-[12px] text-[#6B7684]">{inlineMessage.text}</p>
305→            {inlineMessage.canvasPrompt && (
306→              <button
307→                type="button"
308→                onClick={() => {
309→                  submitPromptToCanvas(inlineMessage.canvasPrompt);
310→                  setInlineMessage(null);
311→                }}
312→                className="flex-shrink-0 text-[12px] font-semibold text-[#FF6B00] active:opacity-70"
313→              >
314→                자세히
315→              </button>
316→            )}
317→          </div>
318→        )}
319→
320→        {/* 볼드 입력바 */}
321→        <AgentControlPulse active={pulseActive}>
322→          <div className="pointer-events-auto relative rounded-[20px] bg-white shadow-[0_-2px_12px_rgba(0,0,0,0.06)]">
323→            {/* 상단 상태 라인 (항상 노출) */}
324→            <div className="flex items-center gap-2 border-b border-[#F2F4F6] px-3 py-1.5">
325→              <button
326→                type="button"
327→                onClick={hasActiveSession ? handleResumeChat : undefined}
328→                className={`flex min-w-0 flex-1 items-center gap-2 text-left ${hasActiveSession ? 'active:bg-[#F7F8FA]' : ''}`}
329→              >
330→                <span className={`h-1.5 w-1.5 rounded-full ${
331→                  isActivelyWorking ? 'bg-[#1D6FDE]' : 'bg-[#16A34A]'
332→                } ${statusDotClass}`} />
333→                <div className="min-w-0">
334→                  <p className={`truncate text-[12px] font-medium ${isActivelyWorking ? 'text-[#4E5968]' : 'text-[#166534]'}`}>
335→                    {dockStatusText}
336→                  </p>
337→                </div>
338→                {shouldShowChevron && (
339→                  <svg className="ml-auto text-[#B0B8C1]" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
340→                    <path d="m9 18 6-6-6-6" />
341→                  </svg>
342→                )}
343→              </button>
344→
345→              <div className="ml-auto flex items-center gap-1">
346→                <button
347→                  type="button"
348→                  onClick={() => setSearchEnabled((prev) => !prev)}
349→                  className={`flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-full transition-colors ${
350→                    searchEnabled
351→                      ? 'bg-[#FFF2E8] text-[#FF6B00]'
352→                      : 'bg-[#F2F4F6] text-[#8B95A1]'
353→                  }`}
354→                  aria-label={searchEnabled ? '인터넷 검색 켜짐' : '인터넷 검색 꺼짐'}
355→                  title={searchEnabled ? '인터넷 검색: 켜짐' : '인터넷 검색: 꺼짐'}
356→                >
357→                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.9" strokeLinecap="round" strokeLinejoin="round">
358→                    <circle cx="12" cy="12" r="9" />
359→                    <path d="M3 12h18" />
360→                    <path d="M12 3a15 15 0 0 1 0 18" />
361→                    <path d="M12 3a15 15 0 0 0 0 18" />
362→                  </svg>
363→                </button>
364→
365→                <button
366→                  type="button"
367→                  onClick={() => navigate('/agent/history', { state: { mode, contextPayload: buildControlContextPayload('') } })}
368→                  className="flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-full bg-[#F2F4F6] text-[#6B7684] transition-colors active:bg-[#E8EBED]"
369→                  aria-label="대화 기록 보기"
370→                  title="대화 기록 보기"
371→                >
372→                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.9" strokeLinecap="round" strokeLinejoin="round">
373→                    <path d="M12 8v5l3 2" />
374→                    <circle cx="12" cy="12" r="9" />
375→                  </svg>
376→                </button>
377→              </div>
378→            </div>
379→
380→            {showSlashMenu && (
381→              <SlashCommandMenu
382→                query={slashQuery}
383→                onSelect={handleSlashCommand}
384→                onClose={() => { setShowSlashMenu(false); setSlashQuery(''); }}
385→                visible={showSlashMenu}
386→              />
387→            )}
388→
389→            <form
390→              onSubmit={handleSubmit}
391→              className="flex h-12 items-center gap-2.5 px-3"
392→            >
393→              <button
394→                type="button"
395→                onClick={() => submitPrompt(suggestedPrompt)}
396→                className="flex h-7 w-7 flex-shrink-0 items-center justify-center rounded-full bg-[#FF6B00] text-white shadow-sm active:scale-95"
397→                aria-label="추천 질문 사용"
398→              >
399→                <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
400→                  <path d="M12 3l2 5 5 2-5 2-2 5-2-5-5-2 5-2 2-5z" />
401→                  <path d="M19 4l.7 1.6 1.6.7-1.6.7-.7 1.6-.7-1.6-1.6-.7 1.6-.7.7-1.6z" />
402→                  <path d="M5.5 15l.7 1.6 1.6.7-1.6.7-.7 1.6-.7-1.6-1.6-.7 1.6-.7.7-1.6z" />
403→                </svg>
404→              </button>
405→
406→              <div className="flex min-w-0 flex-1 items-center gap-1.5">
407→                {activePrefix && (
408→                  <span className="inline-flex shrink-0 items-center gap-1 rounded-full border border-[#FF6B00]/20 bg-[#FFF2E8] px-2.5 py-1 text-[12px] font-semibold text-[#FF6B00]">
409→                    {activePrefix.label}
410→                    <button
411→                      type="button"
412→                      onClick={() => setActivePrefix(null)}
413→                      className="ml-0.5 text-[#FF6B00]/60 hover:text-[#FF6B00]"
414→                      aria-label="명령어 칩 제거"
415→                    >
416→                      ✕
417→                    </button>
418→                  </span>
419→                )}
420→                <input
421→                  type="text"
422→                  value={input}
423→                  onChange={(event) => {
424→                    const val = event.target.value;
425→                    setInput(val);
426→                    if (val.startsWith('/')) {
427→                      setShowSlashMenu(true);
428→                      setSlashQuery(val.slice(1));
429→                    } else {
430→                      setShowSlashMenu(false);
431→                      setSlashQuery('');
432→                    }
433→                  }}
434→                  onKeyDown={(e) => {
435→                    if (showSlashMenu && (e.key === 'ArrowUp' || e.key === 'ArrowDown' || e.key === 'Enter')) {
436→                      e.preventDefault();
437→                    }
438→                    if (e.key === 'Escape' && showSlashMenu) {
439→                      setShowSlashMenu(false);
440→                      setSlashQuery('');
441→                    }
442→                    if (e.key === 'Backspace' && !input && activePrefix) {
443→                      setActivePrefix(null);
444→                    }
445→                  }}
446→                  placeholder={activePrefix ? '내용을 입력하세요' : (input ? placeholder : suggestedPrompt)}
447→                  data-agent-dock-input
448→                  className="min-w-0 flex-1 bg-transparent text-[14px] text-[#191F28] placeholder:text-[#B0B8C1] focus:outline-none"
449→                  aria-label="에이전트 질문 입력"
450→                />
451→              </div>
452→
453→              <button
454→                type="submit"
455→                className="flex h-7 w-7 flex-shrink-0 items-center justify-center rounded-full bg-[#FF6B00] text-white shadow-sm active:scale-95"
456→                aria-label="질문 전송"
457→                disabled={isRouting}
458→              >
459→                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
460→                  <path d="m12 19V5" />
461→                  <path d="m5 12 7-7 7 7" />
462→                </svg>
463→              </button>
464→            </form>
465→          </div>
466→        </AgentControlPulse>
467→
468→        {pendingAction && (
469→          <ActionConfirmDialog
470→            action={pendingAction.action}
471→            onConfirm={() => confirmPendingAction('confirm')}
472→            onCancel={() => confirmPendingAction('cancel')}
473→            onAutoMode={() => confirmPendingAction('auto')}
474→          />
475→        )}
476→      </div>
477→    </div>
478→  );
479→}
