    });
    if (!response.ok) {
      throw new Error('route_failed');
    }
    return response.json();
  }, [mode]);

  if (shouldHide) return null;

  const phaseTextByPhase = {
    thinking: '에이전트 분석 중',
    tool_call: '도구 실행 중',
    answering: '답변 생성 중',
    stopped: '중단됨',
    notice: '답변 생성 중',
    error: '오류 발생',
