                      onError={(event) => {
                        event.currentTarget.src = getHomeIconSrc(DEFAULT_HOME_ICON_KEY);
                      }}
                    />
                  </div>
                  <p className="line-limit-2 text-[18px] font-extrabold leading-7 tracking-[-0.01em] text-[#101828]">
                    {item.meta?.title || item.title}
